macro.artwork_pipeline.generate_schema_n.macro_sql:
{% macro generate_schema_name(custom_schema_name, node) -%}

    {% set allowed_schemas = ['SILVER', 'GOLD', 'DBT_TEST__AUDIT'] %}

    {%- if custom_schema_name is none -%}
        {# No +schema declared on the model; use the target default (SILVER). #}
        {{ target.schema }}
    {%- elif custom_schema_name | upper in allowed_schemas -%}
        {# Approved schema: use verbatim (no prefix concatenation). #}
        {{ custom_schema_name | upper }}
    {%- else -%}
        {{ exceptions.raise_compiler_error(
            "Schema '" ~ custom_schema_name ~ "' is not in the approved list: "
            ~ allowed_schemas | join(', ') ~ ". "
            ~ "Create it via IaC first (infrastructure/create_schemas.sql), "
            ~ "then add to macros/generate_schema_name.sql allowed_schemas."
        ) }}
    {%- endif -%}

{%- endmacro %}

macro.dbt_snowflake.snowflake__generate_.macro_sql:
{% macro snowflake__generate_database_name(custom_database_name=none, node=none) -%}
    {%- if custom_database_name is none -%}
         {%- if node is not none and node|attr('database') -%}
            {%- set catalog_relation = adapter.build_catalog_relation(node) -%}
        {%- elif 'config' in target -%}
            {%- set catalog_relation = adapter.build_catalog_relation(target) -%}
        {%- else -%}
            {%- set catalog_relation = none -%}
        {%- endif -%}
        {%- if catalog_relation is not none
